import { useState, useEffect } from 'react';
import { Container, Card, Stack, Row, Text, Badge, MotionKeyframes, useMotion } from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface CurrentWeather {
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
}

interface ForecastDay {
  day: string;
  condition: string;
  high: number;
  low: number;
}

interface Props {
  location?: string;
  current?: CurrentWeather;
  forecast?: ForecastDay[];
  onSubmit?: (data: unknown) => void;
}

// Weather emoji mapping
const getWeatherEmoji = (condition: string): string => {
  const c = condition.toLowerCase();
  if (c.includes('sunny') || c.includes('clear')) return '☀️';
  if (c.includes('cloud')) return '☁️';
  if (c.includes('rain') || c.includes('wet')) return '🌧️';
  if (c.includes('snow')) return '❄️';
  if (c.includes('wind')) return '💨';
  if (c.includes('thunder') || c.includes('storm')) return '⛈️';
  if (c.includes('fog') || c.includes('mist')) return '🌫️';
  if (c.includes('partly')) return '⛅';
  return '🌤️';
};

export default function GeneratedComponent({
  location = 'San Francisco',
  current = {
    temperature: 72,
    condition: 'Partly Cloudy',
    humidity: 65,
    windSpeed: 12,
  },
  forecast = [
    { day: 'Mon', condition: 'Sunny', high: 75, low: 62 },
    { day: 'Tue', condition: 'Cloudy', high: 70, low: 60 },
    { day: 'Wed', condition: 'Rainy', high: 65, low: 55 },
    { day: 'Thu', condition: 'Partly Cloudy', high: 68, low: 58 },
    { day: 'Fri', condition: 'Sunny', high: 76, low: 63 },
  ],
  onSubmit,
}: Props) {
  const { motionEnabled } = useMotion();
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
  }, []);

  const currentEmoji = getWeatherEmoji(current.condition);
  const forecastItems = forecast.slice(0, 5);

  return (
    <>
      <MotionKeyframes />
      <Container maxWidth="md">
        <Card
          padding={24}
          shadow="md"
          style={{
            animation: mounted && motionEnabled ? animation.slideInUp : 'none',
            background: `linear-gradient(135deg, var(--ggui-color-primary-50, #f0f9ff), var(--ggui-color-primary-100, #e0f2fe))`,
            border: `1px solid var(--ggui-color-primary-200, #bae6fd)`,
          }}
        >
          <Stack direction="vertical" gap={24}>
            {/* Header with Location */}
            <Stack direction="vertical" gap={8}>
              <Text
                variant="h3"
                style={{
                  color: 'var(--ggui-color-primary-900, #0c4a6e)',
                  fontSize: 'var(--ggui-typography-fontSize-lg, 18px)',
                  fontWeight: 'var(--ggui-typography-fontWeight-semibold, 600)',
                }}
              >
                {location}
              </Text>
              <Text
                variant="body"
                style={{
                  color: 'var(--ggui-color-primary-700, #0369a1)',
                  fontSize: 'var(--ggui-typography-fontSize-sm, 14px)',
                }}
              >
                Today's Weather
              </Text>
            </Stack>

            {/* Current Weather - Large Temperature */}
            <Stack direction="horizontal" gap={20} align="center">
              <div
                style={{
                  fontSize: '64px',
                  lineHeight: '1',
                  animation: mounted && motionEnabled ? animation.slideInUp : 'none',
                  animationDelay: motionEnabled ? '100ms' : '0ms',
                }}
              >
                {currentEmoji}
              </div>
              <Stack direction="vertical" gap={8}>
                <div
                  style={{
                    fontSize: 'var(--ggui-typography-fontSize-4xl, 36px)',
                    fontWeight: 'var(--ggui-typography-fontWeight-bold, 700)',
                    color: 'var(--ggui-color-primary-900, #0c4a6e)',
                    lineHeight: '1',
                  }}
                >
                  {current.temperature}°F
                </div>
                <Text
                  style={{
                    color: 'var(--ggui-color-primary-700, #0369a1)',
                    fontSize: 'var(--ggui-typography-fontSize-base, 16px)',
                    fontWeight: 'var(--ggui-typography-fontWeight-medium, 500)',
                  }}
                >
                  {current.condition}
                </Text>
              </Stack>
            </Stack>

            {/* Humidity and Wind - Side by Side */}
            <Row
              gap={16}
              justify="start"
              style={{
                animation: mounted && motionEnabled ? animation.fadeIn : 'none',
                animationDelay: motionEnabled ? '200ms' : '0ms',
              }}
            >
              <Card
                padding={16}
                shadow="sm"
                style={{
                  flex: 1,
                  background: 'var(--ggui-color-surface, #ffffff)',
                  border: `1px solid var(--ggui-color-primary-200, #bae6fd)`,
                }}
              >
                <Stack direction="vertical" gap={8} align="center">
                  <Text
                    style={{
                      fontSize: 'var(--ggui-typography-fontSize-sm, 14px)',
                      color: 'var(--ggui-color-text-secondary, #6b7280)',
                      fontWeight: 'var(--ggui-typography-fontWeight-medium, 500)',
                    }}
                  >
                    Humidity
                  </Text>
                  <div
                    style={{
                      fontSize: 'var(--ggui-typography-fontSize-2xl, 24px)',
                      fontWeight: 'var(--ggui-typography-fontWeight-bold, 700)',
                      color: 'var(--ggui-color-primary-600, #0284c7)',
                    }}
                  >
                    {current.humidity}%
                  </div>
                </Stack>
              </Card>

              <Card
                padding={16}
                shadow="sm"
                style={{
                  flex: 1,
                  background: 'var(--ggui-color-surface, #ffffff)',
                  border: `1px solid var(--ggui-color-primary-200, #bae6fd)`,
                }}
              >
                <Stack direction="vertical" gap={8} align="center">
                  <Text
                    style={{
                      fontSize: 'var(--ggui-typography-fontSize-sm, 14px)',
                      color: 'var(--ggui-color-text-secondary, #6b7280)',
                      fontWeight: 'var(--ggui-typography-fontWeight-medium, 500)',
                    }}
                  >
                    Wind
                  </Text>
                  <div
                    style={{
                      fontSize: 'var(--ggui-typography-fontSize-2xl, 24px)',
                      fontWeight: 'var(--ggui-typography-fontWeight-bold, 700)',
                      color: 'var(--ggui-color-primary-600, #0284c7)',
                    }}
                  >
                    {current.windSpeed} mph
                  </div>
                </Stack>
              </Card>
            </Row>

            {/* Divider */}
            <div
              style={{
                height: '1px',
                background: 'var(--ggui-color-primary-200, #bae6fd)',
              }}
            />

            {/* 5-Day Forecast Header */}
            <Text
              style={{
                fontSize: 'var(--ggui-typography-fontSize-sm, 14px)',
                fontWeight: 'var(--ggui-typography-fontWeight-semibold, 600)',
                color: 'var(--ggui-color-primary-900, #0c4a6e)',
              }}
            >
              5-Day Forecast
            </Text>

            {/* Forecast Strip */}
            <Row
              gap={12}
              justify="start"
              wrap={true}
              style={{
                animation: mounted && motionEnabled ? animation.fadeIn : 'none',
                animationDelay: motionEnabled ? '300ms' : '0ms',
              }}
            >
              {forecastItems.map((day, index) => {
                const delayMs = 300 + index * 50;
                const delayStr = delayMs + 'ms';
                return (
                  <div
                    key={day.day}
                    style={{
                      flex: `0 1 calc(20% - 10px)`,
                      minWidth: '80px',
                    }}
                  >
                    <Card
                      padding={12}
                      shadow="sm"
                      style={{
                        background: 'var(--ggui-color-surface, #ffffff)',
                        border: `1px solid var(--ggui-color-primary-200, #bae6fd)`,
                        textAlign: 'center',
                        animation: mounted && motionEnabled ? animation.scaleIn : 'none',
                        animationDelay: motionEnabled ? delayStr : '0ms',
                        transformOrigin: 'center',
                      }}
                    >
                      <Stack direction="vertical" gap={8} align="center">
                        <Text
                          style={{
                            fontSize: 'var(--ggui-typography-fontSize-sm, 14px)',
                            fontWeight: 'var(--ggui-typography-fontWeight-semibold, 600)',
                            color: 'var(--ggui-color-primary-700, #0369a1)',
                          }}
                        >
                          {day.day}
                        </Text>
                        <div style={{ fontSize: '28px', lineHeight: '1' }}>
                          {getWeatherEmoji(day.condition)}
                        </div>
                        <Text
                          style={{
                            fontSize: 'var(--ggui-typography-fontSize-xs, 12px)',
                            color: 'var(--ggui-color-text-secondary, #6b7280)',
                            lineHeight: '1.2',
                          }}
                        >
                          {day.condition}
                        </Text>
                        <div
                          style={{
                            fontSize: 'var(--ggui-typography-fontSize-sm, 14px)',
                            fontWeight: 'var(--ggui-typography-fontWeight-bold, 700)',
                            color: 'var(--ggui-color-primary-600, #0284c7)',
                          }}
                        >
                          {day.high}°
                        </div>
                        <Text
                          style={{
                            fontSize: 'var(--ggui-typography-fontSize-xs, 12px)',
                            color: 'var(--ggui-color-text-secondary, #6b7280)',
                          }}
                        >
                          {day.low}°
                        </Text>
                      </Stack>
                    </Card>
                  </div>
                );
              })}
            </Row>
          </Stack>
        </Card>
      </Container>
    </>
  );
}

import { useState } from 'react';
import { Container, Card, Stack, Row, Text, Divider } from '@ggui-ai/design/primitives';

interface ForecastItem {
  day: string; // e.g., "Mon", "Tue"
  icon: string; // e.g., "☀️", "☁️", "🌧️"
  high: number;
  low: number;
}

interface Props {
  city?: string;
  currentTemperature?: number;
  currentCondition?: string;
  currentHumidity?: number; // percentage
  currentWindSpeed?: number; // km/h or mph
  forecast?: ForecastItem[];
  onSubmit?: (data: unknown) => void;
}

export default function GeneratedComponent({
  city = "Unknown City",
  currentTemperature = 25,
  currentCondition = "Partly Cloudy",
  currentHumidity = 60,
  currentWindSpeed = 10,
  forecast = [
    { day: "Mon", icon: "☀️", high: 28, low: 18 },
    { day: "Tue", icon: "☁️", high: 26, low: 17 },
    { day: "Wed", icon: "🌧️", high: 22, low: 15 },
    { day: "Thu", icon: "🌤️", high: 24, low: 16 },
    { day: "Fri", icon: "☀️", high: 27, low: 19 },
  ],
  onSubmit
}: Props) {

  const getConditionEmoji = (condition: string) => {
    condition = condition.toLowerCase();
    if (condition.includes("sunny")) return "☀️";
    if (condition.includes("cloudy")) return "☁️";
    if (condition.includes("rain")) return "🌧️";
    if (condition.includes("storm")) return "⛈️";
    if (condition.includes("snow")) return "❄️";
    if (condition.includes("clear")) return "☀️";
    if (condition.includes("partly cloudy")) return "🌤️";
    if (condition.includes("fog")) return "🌫️";
    return "🌡️"; // Default
  };

  return (
    <Container maxWidth="sm" center={true}>
      <Card
        padding="var(--ggui-spacing-lg, 24px)"
        shadow="md"
        style={{
          background: 'var(--ggui-color-surface, #ffffff)',
          borderRadius: 'var(--ggui-radius-lg, 12px)',
          borderColor: 'var(--ggui-color-gray-200, #e5e7eb)',
          borderWidth: '1px',
          borderStyle: 'solid',
        }}
      >
        <Stack direction="vertical" gap={20} align="center">
          {/* Current Weather */}
          <Text
            variant="h2"
            align="center"
            style={{
              color: 'var(--ggui-color-text-primary, #111827)',
              fontSize: 'var(--ggui-typography-fontSize-3xl, 30px)',
              fontWeight: 'var(--ggui-typography-fontWeight-bold, 700)',
            }}
          >
            {city}
          </Text>

          <Text
            style={{
              fontSize: 'var(--ggui-typography-fontSize-4xl, 36px)',
              fontWeight: 'var(--ggui-typography-fontWeight-bold, 700)',
              color: 'var(--ggui-color-primary-600, #0284c7)',
            }}
          >
            {currentTemperature}°C
          </Text>

          <Row gap={8} align="center">
            <Text
              style={{
                fontSize: 'var(--ggui-typography-fontSize-2xl, 24px)',
                lineHeight: '1',
              }}
            >
              {getConditionEmoji(currentCondition)}
            </Text>
            <Text
              style={{
                fontSize: 'var(--ggui-typography-fontSize-xl, 20px)',
                color: 'var(--ggui-color-text-secondary, #6b7280)',
              }}
            >
              {currentCondition}
            </Text>
          </Row>

          <Row gap={16} justify="center">
            <Stack direction="vertical" align="center" gap={4}>
              <Text
                style={{
                  fontSize: 'var(--ggui-typography-fontSize-sm, 14px)',
                  color: 'var(--ggui-color-text-primary, #111827)',
                  fontWeight: 'var(--ggui-typography-fontWeight-medium, 500)',
                }}
              >
                Humidity
              </Text>
              <Text
                style={{
                  fontSize: 'var(--ggui-typography-fontSize-md, 16px)',
                  color: 'var(--ggui-color-text-secondary, #6b7280)',
                }}
              >
                {currentHumidity}%
              </Text>
            </Stack>
            <Stack direction="vertical" align="center" gap={4}>
              <Text
                style={{
                  fontSize: 'var(--ggui-typography-fontSize-sm, 14px)',
                  color: 'var(--ggui-color-text-primary, #111827)',
                  fontWeight: 'var(--ggui-typography-fontWeight-medium, 500)',
                }}
              >
                Wind
              </Text>
              <Text
                style={{
                  fontSize: 'var(--ggui-typography-fontSize-md, 16px)',
                  color: 'var(--ggui-color-text-secondary, #6b7280)',
                }}
              >
                {currentWindSpeed} km/h
              </Text>
            </Stack>
          </Row>

          <Divider margin="var(--ggui-spacing-md, 16px)" />

          {/* 5-Day Forecast */}
          <Row justify="around" fullWidth={true} wrap={true} gap={16}>
            {forecast.map((dayForecast, index) => (
              <Stack key={index} direction="vertical" align="center" gap={4} style={{ minWidth: '60px' }}>
                <Text
                  style={{
                    fontSize: 'var(--ggui-typography-fontSize-sm, 14px)',
                    color: 'var(--ggui-color-text-primary, #111827)',
                    fontWeight: 'var(--ggui-typography-fontWeight-medium, 500)',
                  }}
                >
                  {dayForecast.day}
                </Text>
                <Text
                  style={{
                    fontSize: 'var(--ggui-typography-fontSize-xl, 20px)',
                    lineHeight: '1',
                  }}
                >
                  {dayForecast.icon}
                </Text>
                <Text
                  style={{
                    fontSize: 'var(--ggui-typography-fontSize-sm, 14px)',
                    color: 'var(--ggui-color-primary-700, #0369a1)',
                    fontWeight: 'var(--ggui-typography-fontWeight-semibold, 600)',
                  }}
                >
                  {dayForecast.high}°
                </Text>
                <Text
                  style={{
                    fontSize: 'var(--ggui-typography-fontSize-xs, 12px)',
                    color: 'var(--ggui-color-text-secondary, #6b7280)',
                  }}
                >
                  {dayForecast.low}°
                </Text>
              </Stack>
            ))}
          </Row>
        </Stack>
      </Card>
    </Container>
  );
}
